attachments.value:
{%raw%}
<div style="overflow: auto; width: 100%; height: 100%; background-color: #000000; color: #ffffff; padding: 10px 10px 0px 20px;">

{%-
  set cfxql_query2 = "conversationId = '"+ conversation_id + "' and tool_name is not null  GET USER_ID,persona,message,conversationLabel,timestamp,type,llm,tool_name,token_usage_input_tokens,token_usage_cache_tokens,token_usage_output_tokens,tool_content,codeBlocks"
-%}


{%-
    set convs = engine.query_stream_data("rda_chat_sessions", cfxql_query=cfxql_query2, sorting=[{"timestamp": "asc"}], limit=1000, max_rows=1000)
-%}
<ol>
{%- for row in convs -%}

<li><p>Tool Call: <b>{{row["tool_name"].strip()}}</b>

 <pre>{{ row["codeBlocks"].strip('{}').split(":", 1)[1] | trim | trim('"') | replace('\\n', '\n') | replace('\\"', '"') }}</pre>
 <br/>

{%- endfor -%}
</ol>
</div>



{%endraw%}
